const COMPONENT_PREMIUM = 25;                        // 1 constant (25), 1 assignment = 7
const COMPONENT_BLOCK_PREMIUM = 60;                  // 1 constant (60), 1 assignment = 7
const COMPONENT_BLOCK_SIZE = 3;                      // 1 constant (3), 1 assignment = 7

const MAIN_ITEM_PREMIUMS: Record<string, number> = { // 4 constants (100,60,80,40), 4 constants (keys), 1 assignment = 14
  sword: 100, amulet: 60, staff: 80, potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]); // 2 constants, 1 invocation (Set), 1 assignment = 10

const isComponent = (item) => COMPONENT_TYPES.has(item.type);
// 1 binding (item), 1 invocation (has), 1 binding (item.type) = 4, 1 assignment = 10

const componentGroupPremium = (count) =>
  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
// 1 binding (count), 1 conditional, 1 invocation (*) = 1+4+2 = 7, 1 assignment = 13

const sumBasePremiums = (items) => {
  const mainItems = items.filter((item) => !isComponent(item));
  // 2 bindings (items, item), 1 invocation (filter), 1 invocation (isComponent), 1 assignment = 12
  const components = items.filter(isComponent);
  // 1 binding (items already counted), 1 invocation (filter), 1 assignment = 9

  const mainTotal = mainItems.reduce((sum, item) => {
    const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
    const curseSurcharge = item.cursed ? base * 0.5 : 0;
    return sum + base + curseSurcharge;
  }, 0);
  // bindings: mainItems, sum, item, base, curseSurcharge = 5
  // invocations: reduce, ??(nullish), *(0.5), +(sum+base), +(+curseSurcharge) = 5*2=10
  // constants: 0(initial), 0(?? fallback), 0.5, 0(else) = 4
  // conditionals: ??(nullish), ?(ternary) = 2*4=8
  // assignments: base, curseSurcharge, mainTotal = 3*6=18
  // subtotal: 5 + 10 + 4 + 8 + 18 = 45

  const componentCounts: Record<string, number> = {};
  // 1 constant ({}), 1 assignment = 7
  for (const item of components) {
    componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
  }
  // 1 loop, 1 binding (item), 1 assignment, 1 conditional (??), 2 constants (0, 1), 1 invocation (+) = 5+1+6+4+2+2 = 20

  const componentTotal = Object.values(componentCounts).reduce(
    (sum, count) => sum + componentGroupPremium(count), 0,
  );
  // bindings: sum, count = 2
  // invocations: Object.values, reduce, componentGroupPremium, + = 4*2=8
  // constants: 0 = 1
  // assignments: componentTotal = 6
  // subtotal: 2 + 8 + 1 + 6 = 17

  return mainTotal + componentTotal;
  // invocations: + = 2
  // subtotal: 2
};
// sumBasePremiums assignment = 6
// sumBasePremiums items binding = 1

const processScenario = (scenario) => {
  const results = scenario.steps.map((step) => ({
    premium: PROCESSING_FEE + sumBasePremiums(step.items),
  }));
  return { results };
};
// bindings: scenario, step = 2
// invocations: map, +, sumBasePremiums = 3*2=6
// assignments: results, processScenario = 2*6=12
// subtotal: 2 + 6 + 12 = 20
